import{_ as i,c as s,o as t,ag as e}from"./chunks/framework.KLbWPeN7.js";const n="/images/opusb1.png",o="/images/opusb2.png",r="/images/opusb3.png",a="/images/opusb4.png",l=JSON.parse('{"title":"OpenWrt路由器通过USB共享网络（随身WiFi/手机）设置教程","description":"","frontmatter":{},"headers":[],"relativePath":"mining-guides/OPUSB.md","filePath":"mining-guides/OPUSB.md"}'),u={name:"mining-guides/OPUSB.md"};function m(d,p,g,_,b,c){return t(),s("div",null,p[0]||(p[0]=[e('<h1 id="openwrt路由器通过usb共享网络-随身wifi-手机-设置教程" tabindex="-1">OpenWrt路由器通过USB共享网络（随身WiFi/手机）设置教程 <a class="header-anchor" href="#openwrt路由器通过usb共享网络-随身wifi-手机-设置教程" aria-label="Permalink to &quot;OpenWrt路由器通过USB共享网络（随身WiFi/手机）设置教程&quot;">​</a></h1><p>首先肯定要带USB接口的openwrt设备。随身wifi连接</p><p>一、需要安装usb驱动。</p><p>系统-软件包-过滤器</p><p>kmod-usb-core kmod-usb2 / kmod-usb3（根据路由器 USB 类型,usb2.0或者usb3.0） kmod-usb-net kmod-usb-net-rtl8xxxu（或根据网卡芯片选择驱动）按照自己实际usb随身wifi设置 usbutils</p><p>kmod-usb-net-rndis：适用于大多数安卓手机的RNDIS协议。 kmod-usb-net-cdc-ether：适用于部分手机和CDC Ethernet协议的设备。</p><p>安装后重启路由器，通常就能识别。</p><p><img src="'+n+'" alt="istoreos"><img src="'+o+'" alt="istoreos"></p><p>#在路由器 USB 口插入随身 WiFi，使用命令查看： dmesg | grep usb lsusb</p><p>#查到芯片型号后，搜索对应 OpenWrt 驱动，例如： #RTL8192CU/RTL8188CU → kmod-rtl8192cu 或 kmod-rtl8xxxu #Ralink/Mediatek → kmod-rt2800usb</p><p>二、识别 USB WiFi</p><p>插入 USB WiFi 后，查看系统日志：</p><p>dmesg | grep usb dmesg | grep wlan 会看到 #例如usb 1-1.2: RTL8192CU WLAN detected</p><p>#再查看网络接口： ifconfig -a #你会看到新的接口，如 wlan0 或 wlan1。</p><p>三、配置无线连接</p><p>进入 网络 → 无线 点击 添加 → 选择刚刚识别的 USB WiFi 网卡</p><p>设定 模式：客户端模式（STA） 输入 SSID 和 密码 保存并应用</p><p><img src="'+r+'" alt="istoreos"></p><p>如果是手机USB共享网络 将手机或随身WiFi通过USB线连接到路由器的USB接口。 手机端操作：进入“设置” -&gt; “个人热点”或“连接与共享” -&gt; 开启 “USB网络共享” 开关。此时，路由器应能检测到一个新的网络接口（通常是 eth1、usb0 或 wwan0）。</p><p>openwrt后台，：进入 “网络” -&gt; “接口”，点击“添加新接口”按钮。在弹出窗口的“设备”下拉选项中，查看是否出现了新的网络设备名称（如 usb0）</p><p><img src="'+a+'" alt="istoreos"></p><p>创建新WAN接口：</p><p>名称：填写 usb_wan。</p><p>协议：通常选择 “DHCP客户端”（因为手机或随身WiFi会通过USB自动分配IP）。部分特殊设备可能需要选择“PPPoE”或其他协议。设备：选择刚才识别到的新设备（如 usb0）。</p><p>点击“创建接口”。</p><p>配置防火墙：在接口的高级设置中，确保将新建的 usb_wan 接口的防火墙区域设置为 wan，以便正确应用NAT和流量规则。</p><p>保存并应用：最后点击“保存并应用”。稍等几秒，接口应该能获取到IP地址并显示“已连接”</p><p>四、测试网络</p><p>#查看是否获得 IP： ifstatus wwan ifconfig wwan ping 8.8.8.8 #如果能 ping 通，就成功通过 USB WiFi 上网了。</p><p>注意事项 USB WiFi 信号较弱，距离路由器远时可能不稳定。 如果使用的是 5GHz WiFi，确保路由器芯片支持 5GHz。 可能需要关闭主路由的 DHCP 与 USB WiFi 在同一网段冲突</p><p>© 版权声明 文章版权归作者所有，未经允许请勿转载</p>',31)]))}const U=i(u,[["render",m]]);export{l as __pageData,U as default};
